import React, { useEffect, useState, useRef } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import { 
  Heart, ListPlus, Trash2, Play, Pause, SkipForward, SkipBack, 
  Trophy, Home as HomeIcon, Search, Library, Music2, User
} from 'lucide-react';

const Home = () => {
  const [songs, setSongs] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(-1);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [hoveredCard, setHoveredCard] = useState(null);
  
  const audioRef = useRef(null);
  const navigate = useNavigate();
  const loggedInUser = JSON.parse(localStorage.getItem('user'));

  const currentSong = currentIndex !== -1 ? songs[currentIndex] : null;

  useEffect(() => {
    fetchSongs();
  }, []);

  const fetchSongs = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/songs');
      setSongs(res.data);
    } catch (err) { console.error("Lỗi tải nhạc:", err); }
  };

  const handleLike = async (songId) => {
    if (!loggedInUser) return alert("Vui lòng đăng nhập!");
    try {
      const res = await axios.post(`http://localhost:5000/api/songs/like/${songId}`, {
        userId: loggedInUser._id || loggedInUser.id
      });
      setSongs(songs.map(s => s._id === songId ? res.data : s));
    } catch (err) { console.error(err); }
  };

  const handleCreatePlaylist = async () => {
    if (!loggedInUser) return alert("Vui lòng đăng nhập!");
    const title = prompt("Tên Playlist mới của bạn:");
    if (!title) return;
    try {
      await axios.post('http://localhost:5000/api/songs/playlists', {
        title, userId: loggedInUser._id, songIds: []
      });
      alert("Đã tạo Playlist thành công! 🎉");
    } catch (err) { alert("Lỗi tạo playlist"); }
  };

  const playSong = (index) => { setCurrentIndex(index); setIsPlaying(true); };
  
  const togglePlay = () => {
    if (isPlaying) audioRef.current.pause();
    else audioRef.current.play();
    setIsPlaying(!isPlaying);
  };

  const formatTime = (t) => {
    if (isNaN(t)) return "0:00";
    const m = Math.floor(t / 60);
    const s = Math.floor(t % 60);
    return `${m}:${s < 10 ? '0' : ''}${s}`;
  };

  return (
    <div style={containerStyle}>
      {/* 1. SIDEBAR LEFT */}
      <div style={sidebarStyle}>
        <div style={logoStyle}>P2TUNES</div>
        <div style={menuGroup}>
          <div style={menuItemActive}><HomeIcon size={20}/> Trang chủ</div>
          <div style={menuItem}><Search size={20}/> Tìm kiếm</div>
          <div style={menuItem} onClick={() => navigate('/ranking')}><Trophy size={20}/> Bảng xếp hạng</div>
        </div>
        <div style={menuGroup}>
          <p style={menuTitle}>THƯ VIỆN</p>
          <div style={menuItem}><Library size={20}/> Playlist của bạn</div>
          <div style={menuItem}><Heart size={20}/> Bài hát đã thích</div>
          <button onClick={handleCreatePlaylist} style={sidebarAddBtn}>
            <ListPlus size={18} /> <b>TẠO PLAYLIST</b>
          </button>
        </div>
      </div>

      {/* 2. MAIN CONTENT */}
      <div style={mainContentStyle}>
        {/* Hero Banner */}
        <div style={heroBanner}>
          <div style={{zIndex: 2}}>
            <h1 style={{fontSize: '40px', margin: 0}}>Chào mừng trở lại, {loggedInUser?.username || 'Bạn'}!</h1>
            <p style={{opacity: 0.8, fontSize: '18px'}}>Khám phá những giai điệu mới nhất dành riêng cho bạn hôm nay.</p>
          </div>
          <div style={heroOverlay}></div>
        </div>

        {/* Section: Khám phá */}
        <div style={{padding: '30px'}}>
          <h2 style={{marginBottom: '20px', display: 'flex', alignItems: 'center', gap: '10px'}}>
            <Music2 color="#1db954" /> Dành cho bạn
          </h2>
          
          <div style={songGrid}>
            {songs.map((song, index) => (
              <div 
                key={song._id} 
                style={{
                  ...songCardStyle,
                  transform: hoveredCard === song._id ? 'translateY(-10px)' : 'none',
                  backgroundColor: hoveredCard === song._id ? '#282828' : '#181818'
                }}
                onMouseEnter={() => setHoveredCard(song._id)}
                onMouseLeave={() => setHoveredCard(null)}
              >
                <div style={cardImageWrapper}>
                  <img src={`http://localhost:5000${song.imageUrl}`} style={cardImg} alt="cover" />
                  {hoveredCard === song._id && (
                    <button onClick={() => playSong(index)} style={cardPlayBtn}>
                      <Play fill="black" size={24} />
                    </button>
                  )}
                </div>
                <div style={{marginTop: '15px'}}>
                  <div style={songTitle}>{song.title}</div>
                  <div style={songArtist}>{song.artist}</div>
                </div>
                
                <div style={cardFooter}>
                   <div onClick={() => navigate(`/profile/${song.userId}`)} style={uploaderLink}>
                     {song.uploaderName || "User"}
                   </div>
                   <button onClick={() => handleLike(song._id)} style={likeBtn}>
                      <Heart 
                        size={18} 
                        fill={song.likes?.includes(loggedInUser?._id) ? "#1db954" : "none"} 
                        color={song.likes?.includes(loggedInUser?._id) ? "#1db954" : "#888"}
                      />
                      <span style={{fontSize: '12px'}}>{song.likes?.length || 0}</span>
                   </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* 3. MUSIC PLAYER BAR (Glassmorphism) */}
      {currentSong && (
        <div style={playerBarStyle}>
          <div style={playerLeft}>
            <img src={`http://localhost:5000${currentSong.imageUrl}`} style={playerImg} alt="" />
            <div>
              <div style={{fontWeight: 'bold', fontSize: '14px'}}>{currentSong.title}</div>
              <div style={{fontSize: '12px', color: '#b3b3b3'}}>{currentSong.artist}</div>
            </div>
          </div>

          <div style={playerCenter}>
            <div style={controls}>
              <SkipBack size={22} style={iconBtn} onClick={() => setCurrentIndex((currentIndex - 1 + songs.length) % songs.length)} />
              <button onClick={togglePlay} style={playMainBtn}>
                {isPlaying ? <Pause size={24} fill="black" /> : <Play size={24} fill="black" />}
              </button>
              <SkipForward size={22} style={iconBtn} onClick={() => setCurrentIndex((currentIndex + 1) % songs.length)} />
            </div>
            <div style={progressArea}>
              <span style={timeText}>{formatTime(currentTime)}</span>
              <input 
                type="range" min="0" max={duration || 0} value={currentTime} 
                onChange={(e) => audioRef.current.currentTime = e.target.value}
                style={progressBar} 
              />
              <span style={timeText}>{formatTime(duration)}</span>
            </div>
            <audio ref={audioRef} src={`http://localhost:5000${currentSong.songUrl}`} autoPlay onEnded={() => setCurrentIndex((currentIndex + 1) % songs.length)} onTimeUpdate={() => setCurrentTime(audioRef.current.currentTime)} onLoadedMetadata={() => setDuration(audioRef.current.duration)} />
          </div>

          <div style={playerRight}>
             <User size={20} style={{cursor: 'pointer'}} onClick={() => navigate(`/profile/${loggedInUser?._id}`)} />
          </div>
        </div>
      )}
    </div>
  );
};

/* --- STYLES OBJECT --- */
const containerStyle = { display: 'flex', height: '100vh', backgroundColor: '#000', color: '#fff', fontFamily: "'Inter', sans-serif", overflow: 'hidden' };
const sidebarStyle = { width: '260px', backgroundColor: '#000', padding: '24px', display: 'flex', flexDirection: 'column', gap: '30px' };
const logoStyle = { fontSize: '28px', fontWeight: '900', color: '#1db954', letterSpacing: '-1px' };
const menuGroup = { display: 'flex', flexDirection: 'column', gap: '15px' };
const menuTitle = { fontSize: '12px', fontWeight: 'bold', color: '#b3b3b3', letterSpacing: '1px' };
const menuItem = { display: 'flex', alignItems: 'center', gap: '15px', color: '#b3b3b3', cursor: 'pointer', fontWeight: '600', transition: '0.2s', padding: '5px 0' };
const menuItemActive = { ...menuItem, color: '#fff' };
const sidebarAddBtn = { marginTop: '10px', background: '#fff', border: 'none', padding: '12px', borderRadius: '25px', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px', fontSize: '12px' };

const mainContentStyle = { flex: 1, overflowY: 'auto', background: 'linear-gradient(to bottom, #222, #121212)', paddingBottom: '120px' };
const heroBanner = { height: '300px', padding: '60px 40px', position: 'relative', display: 'flex', alignItems: 'flex-end', background: 'linear-gradient(transparent, rgba(0,0,0,0.7)), url("https://images.unsplash.com/photo-1470225620780-dba8ba36b745?auto=format&fit=crop&w=1000&q=80")', backgroundSize: 'cover', backgroundPosition: 'center', borderRadius: '0 0 30px 30px', margin: '0 20px' };
const heroOverlay = { position: 'absolute', top: 0, left: 0, right: 0, bottom: 0, background: 'rgba(0,0,0,0.3)', borderRadius: '0 0 30px 30px' };

const songGrid = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: '24px' };
const songCardStyle = { padding: '16px', borderRadius: '12px', transition: '0.3s ease', cursor: 'pointer' };
const cardImageWrapper = { position: 'relative', width: '100%', aspectRatio: '1/1', borderRadius: '8px', overflow: 'hidden', boxShadow: '0 8px 24px rgba(0,0,0,0.5)' };
const cardImg = { width: '100%', height: '100%', objectFit: 'cover' };
const cardPlayBtn = { position: 'absolute', bottom: '10px', right: '10px', width: '48px', height: '48px', borderRadius: '50%', backgroundColor: '#1db954', border: 'none', display: 'flex', alignItems: 'center', justifyContent: 'center', boxShadow: '0 8px 16px rgba(0,0,0,0.3)', cursor: 'pointer' };
const songTitle = { fontWeight: 'bold', fontSize: '16px', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' };
const songArtist = { color: '#b3b3b3', fontSize: '14px', marginTop: '4px' };
const cardFooter = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '15px' };
const uploaderLink = { fontSize: '12px', color: '#1db954', fontWeight: '600' };
const likeBtn = { background: 'none', border: 'none', color: '#888', display: 'flex', alignItems: 'center', gap: '5px', cursor: 'pointer' };

const playerBarStyle = { position: 'fixed', bottom: '20px', left: '20px', right: '20px', height: '90px', background: 'rgba(24, 24, 24, 0.85)', backdropFilter: 'blur(15px)', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '45px', display: 'flex', alignItems: 'center', padding: '0 30px', zIndex: 1000 };
const playerLeft = { width: '30%', display: 'flex', alignItems: 'center', gap: '15px' };
const playerImg = { width: '56px', height: '56px', borderRadius: '8px', objectFit: 'cover' };
const playerCenter = { flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center' };
const controls = { display: 'flex', alignItems: 'center', gap: '24px', marginBottom: '8px' };
const playMainBtn = { width: '40px', height: '40px', borderRadius: '50%', backgroundColor: '#fff', border: 'none', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer' };
const iconBtn = { cursor: 'pointer', color: '#b3b3b3', transition: '0.2s' };
const progressArea = { display: 'flex', alignItems: 'center', gap: '10px', width: '100%', maxWidth: '500px' };
const timeText = { fontSize: '11px', color: '#a7a7a7', minWidth: '35px' };
const progressBar = { flex: 1, accentColor: '#1db954', height: '4px', cursor: 'pointer' };
const playerRight = { width: '30%', display: 'flex', justifyContent: 'flex-end', gap: '20px', color: '#b3b3b3' };

export default Home;
